import{c as p,Q as a,j as i,m as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"致尼科洛","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/169-致尼科洛.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/169-致尼科洛.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/lower/169-致尼科洛.md"};function c(l,e,o,s,m,d){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="致尼科洛" tabindex="-1">致尼科洛 <a class="header-anchor" href="#致尼科洛" aria-label="Permalink to &quot;致尼科洛&quot;">​</a></h1><p>致尼科洛 · 马基雅维利 按照我们的命令，出使威尼斯应做之事 1525年8月19日议决</p><p>尼科洛： 我们只向你稍微交代几句，因为我们知道你在许多比目前更困难的事</p><p>派往威尼斯 务中已展示出你的明智审慎和经验丰富，而且因为你完全清楚我们派你去 威尼斯的目的。为了不放弃委托人的责任，我们准备了这些与我们打算派 你前往威尼斯以我们的名义执行的使命相关的话。你要尽量迅速、简便地 赶到威尼斯，愿我们的主上帝保佑你平安到达那里。到达之后，你要做的 头一件事是去拜访费尔特雷主教，就是驻该共和国的教廷大使，你有罗马 寄给他的信件；把信交给他后，我们希望你充分发挥你的能力，想办法拿 到附于他那封信中的一封信。这封信是贝内代托 · 因吉拉米从安科纳写给 我们的信件中的一封，他在其中详细地叙述了整个事件的始末。为了更充 分地说明这个案子，我们曾把这封信寄到罗马；他们在罗马把它附于你所 携带的那封致教廷大使的信里。我们告诉你这件事是因为，这封信在某些 地方同目击者的证词有所出入，这或许会引起怀疑和造成困难，而不是帮 我们解决问题。 教廷大使读了这封信后，你必须从他手里拿回来，说它纯属多余，因 为写这封信的几个年轻人本人就在这里，可以通过口头更简明扼要地陈述 他们的案子。然后讨论采取什么措施，你要听取教座大人的建议，然后你 要和教座大人一起——假如他愿意陪同你的话——或者独自去拜见总督阁 下和威尼斯议会成员，你带有一道圣座的简令和一封我们崇高执政团的信 给他们，你要按照惯有的礼节把这2份文件呈递给他们。假如你获得接见 和被允许发言，你要以我们的名义向他们揭露，在他们的港口一个威尼斯 人无视他们共和国与我们共和国之间存在的真诚友谊，对我们3个像平常 一样携有一笔从黎凡特带来的钱、从拉古萨前来的年轻人犯下了出于一切 预料之外的勒索和抢劫罪行。你要凭借你能运用的最强烈和最有效的语 句，也就是以你的精明审慎你认为最有助于达成我们所渴求之结果的语 句，要求归还他们所损失的财物，收回他们被以暴力剥夺和偷走的东西。 你还要带上安科纳和其他地方的目击者的证词，你要看准你认为最适 当的时机运用这些证词。你还要带上那3个财物被夺走的年轻人中的2人， 以便你可以随时说明准确无误的事实，而且你要随时让他们在你身边，勇</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>派往威尼斯 敢地面对任何企图否认事实的人。 这就是我们此刻想到的要告诉你的一切，即便这些话也许是多余的， 因为我们相信你完全清楚我们的愿望，较之我们上面告诉你的这些话，你 更清楚地知道如何把我们的愿望变成现实。我们对你抱有完全的信任，希 望总督阁下像我们听说的那样，出于自己的大公至正以及你的不懈努力听 审这一案子，把该犯投进监狱，你要带着我们所要求的补偿及时返回。</p><p>佛罗伦萨城羊毛业行会理事</p><p>陈 述</p><p>我们近日从君士坦丁堡回来的几位公民和商人报告了一个蛮横无耻的 事件，极令我们感到不快；我们祈愿阁下出于对我们的仁慈，以及您天生 的正义感，也会同样感到不快。这一事件叙述如下。 这几位商人带着相当数量的钱财，乘坐一艘双桅帆船从拉古萨到了贵 国的莱萨尼港口；在那里他们碰到陪同土耳其大使的威尼斯公民焦万 · 巴 蒂斯塔 · 多纳蒂。焦万 · 巴蒂斯塔让人把这几位商人带到他跟前，用某些 不法的理由威胁要处死他们，尽管他们丝毫没有冒犯他。在对他们进行了 我们羞于启齿复述的侮辱后，他最后强迫他们缴纳了1500金达克特的赎 金，这是他以最浅薄的借口从他们那里勒索的钱财。这一暴行在我们看来 要更加严重，因为它是一个我们从未冒犯过的人横加给我们的，而且是在 贵国的领土上，我们是一直努力用各种帮助来博得贵国的好意的。我们对 这一暴行如何痛心疾首，任何人听到它会有什么想法，我们深知阁下至公 至正、智慧绝伦，所以我们认为无需长篇大论地去说明。 我们希望这番陈述能引起阁下对这个事件的注意，相信您不会忘记我 们之间的友谊，不会忘记对贵共和国的期待，我们请求您重视我国对您的 忠诚；关照我们的这几位商人让他们获得赔偿；说得不那么刺耳，他们没</p><p>有被作为朋友对待，而是经历了一桩匪夷所思的暴行。我们最亲爱的公民同 胞尼科洛 ·马基雅维利为了这个目的前往威尼斯，将以我们的名义和代表我 们的商人，亲口向您解释整个事件，如实地向您讲述事件发生的过程。 我们祈愿阁下相信，当前最让我们愉快的事是下令偿还这几位商人被 夺走的钱财，以便人人都知道这一恶行直接违背了您的意志。如果阁下惯 有的公义以及您对我们年深日久的善意给予这一恩典，您就做了一件与您 的地位相称的事，一件最令我们感到愉快的事；我们会把它作为一桩恩惠 接受下来，等有机会的时候，我们是不会忘记报答的。再会。 \u2028派往威尼斯</p><p>围攻克雷莫纳期间出访盟军</p><p>1526年8月</p><p>在这场使意大利沦为废墟的战争中，教皇、威尼斯人和法国 人结成同盟与神圣罗马帝国皇帝查理五世作对，对于该同盟来说， 这场战争的结局是灾难性的。它已构成一项极为有趣的历史研究课 题，其中许多事件非常有研究价值，比如说罗马之劫、教皇之囚， 以及佛罗伦萨从共和国变为君主国。著名史家圭恰迪尼是教皇派驻 同盟军队的司令，马基雅维利奉佛罗伦萨政府之命前去接近他。圭 恰迪尼、马基雅维利和弗朗切斯科 · 韦托里的公务信件和私人信 件，为当时诸多事务中的密谋提供了极珍贵的说明。 从圭恰迪尼的这篇训令来看，马基雅维利此时似乎待在他身 边，不管是马基雅维利自愿如此，或是由于佛罗伦萨政府授命他如 此的缘故。这篇训令的日期是围攻克雷莫纳期间，即1526年8月。</p><p>训 令</p><p>教皇驻同盟军司令弗朗切斯科 ·圭恰迪尼致马基雅维利</p><p>我派您去克雷莫纳有两个原因；第一，尽量确切地搞清楚那个计划有 几分成功的把握；第二，若五六天之内该城不投降，要不遗余力地放弃攻 击。因此，就第一点而言，为了彻底知晓情况，您除了其他的努力之外， 还有一封我致督政官①的委任状，您要告诉他您此行的第一个目的，真诚</p><p>①威尼斯督政官皮耶罗 ·达 ·佩萨罗。——中译者注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>围攻克雷莫纳期间出访盟军 地恳求他告诉您他对事情的想法,以及公爵^{\\textcircled}1 的看法是什么;让他知道他 可以像和我本人说话那样畅所欲言。 对于第二个目标,当从督政官的回答中获得提示时,您要以我的名义 问他,假如这个地方五六天之内拿不下来,那么他认为应该做什么。您可 以对他说,圣座、威尼斯政府以及军队的指挥官们都认为,再在克雷莫纳 城下浪费时间有百害无一利,因为这会导致失去攻占热那亚的机会,而这 正是整个计划中最重要的目标;只要军队留在克雷莫纳城下,热那亚就不 可能拿下,因为单凭舰队不足以拿下热那亚。萨卢佐侯爵的4000人虚弱无 力,现在更是如此,因为在亚历山德里亚的西班牙人据说已进入热那亚; 此外,我们不认为侯爵愿意率领这么少的兵力挺进热那亚。请提醒他注 意,我们已引来了一支数量庞大的瑞士军队,而且不得不让2000名格劳宾 登人前来。这么多部队的聚集,在我们看来是一种巨大的损失,会引起无 法弥补的巨大混乱,尤其是考虑到瑞士人,他们只要数量一多,就会每天 肆意地做出骚扰行为。许多瑞士人撤走了,但花费依然如故,甚至当军队 减员时,开支每天还在增加。现在马上就要迎来冬季;我们将会面临西班 牙援兵的压力,据最新消息说,西班牙援兵一两天之内就要出发。如果这 些事发生在我们取得热那亚之前,或者把敌人逐出米兰之前,那么我们的 计划将会被严重打乱。因此,您必须力劝督政官大人,万一五六天之内拿 不下这座城市,要尽一切努力撤围。如果督政官大人认为您合适去拜会总 督,您就照办;但是您去拜会时必须极为慎重,不要让他知道我的意见以 及指挥官们的意见。只是跟他说,圣座给我来信说,由于上述原因,似乎 不宜再浪费时间;但无论如何,这个决定得交给圣座大人的智慧去做;不 过,就我而言,我觉得最好让他知道圣座的看法。这些话您都不要向总督 说起,除非督政官建议您说,而且说的时候切勿惹恼他。 寄信来,要寄的信件交给督政官办理。</p><p>\\ textcircled1 乌尔比诺公爵弗朗切斯科·马里亚·德拉·罗韦雷,威尼斯军队的总指挥。——英译本注</p><p>出访弗朗切斯科 · 圭恰迪尼</p><p>摩德纳，1526年11月</p><p>训 令</p>',23)])])}const _=p(r,[["render",c]]);export{h as __pageData,_ as default};
